208→  keyword: '',
209→  snippet: '',
210→  category: 'general',
211→  tags: [],
212→};
213→
214→const FORM_TAG_OPTIONS = SNIPPET_TAGS.map(t => ({
215→  label: t.label,
216→  value: t.value,
217→}));
218→
219→const FORM_CATEGORY_OPTIONS = SNIPPET_CATEGORIES.map(c => ({
