514→        style: 'cancel',
515→        onAction: () => {},
516→      },
517→    });
518→  }, [
519→    selectedEntry,
520→    confirmAlert,
521→    showHUD,
522→  ]);
523→
524→  const handleFormSubmit = useCallback(
525→    (form: SnippetFormState) => {
526→      if (subView === 'edit' && editingSnippet) {
527→        setEntries(prev => {
528→          const next = prev.map(e =>
529→            e.id === editingSnippet.id
530→              ? {
531→                  ...e,
532→                  name: form.name,
533→                  keyword: form.keyword,
534→                  content: form.snippet,
535→                  category: form.category,
536→                  tags: form.tags.map(t => {
537→                    const found = SNIPPET_TAGS.find(st => st.value === t);
538→                    return {
539→                      text: found?.label ?? t,
540→                      color: found?.color,
541→                    };
542→                  }),
543→                }
544→              : e);
545→          saveSnippets(next);
546→          return next;
547→        });
548→        showHUD({
549→          icon: <SnippetHUDIcon />,
550→          title: 'Snippet Updated',
551→        });
552→      } else {
553→        const newEntry: SnippetEntry = {
554→          id: crypto.randomUUID(),
555→          name: form.name,
556→          keyword: form.keyword,
557→          content: form.snippet,
558→          category: form.category,
559→          tags: form.tags.map(t => {
560→            const found = SNIPPET_TAGS.find(st => st.value === t);
561→            return { text: found?.label ?? t };
562→          }),
563→          createdAt: new Date(),
564→        };
565→        setEntries(prev => {
566→          const next = [
567→            newEntry,
568→            ...prev,
569→          ];
570→          saveSnippets(next);
571→          return next;
572→        });
573→        showHUD({
574→          icon: <SnippetHUDIcon />,
575→          title: 'Snippet Created',
576→        });
577→      }
578→      setSubView('list');
579→      setEditingSnippet(undefined);
580→    },
581→    [
582→      subView,
583→      editingSnippet,
584→      showHUD,
585→    ],
586→  );
587→
588→  const toggleActions = useCallback(() => {
589→    setActionsOpen(prev => !prev);
590→  }, []);
591→
592→  const closeActions = useCallback(() => {
593→    setActionsOpen(false);
594→  }, []);
595→
596→  const handleEscape = useCallback(() => {
597→    if (subView !== 'list') {
598→      setSubView('list');
599→      setEditingSnippet(undefined);
600→    }
601→  }, [subView]);
602→
603→  useKeyboardShortcut(
604→    {
605→      key: 'k',
606→      meta: true,
607→    },
608→    toggleActions,
609→    {
610→      enabled: subView === 'list',
611→    },
612→  );
613→  useKeyboardShortcut(
614→    {
615→      key: 'c',
616→      meta: true,
617→    },
618→    handleCopy,
619→    {
620→      enabled: subView === 'list',
621→    },
622→  );
623→  useKeyboardShortcut(
624→    {
625→      key: 'n',
626→      meta: true,
627→    },
628→    handleCreate,
629→    {
630→      enabled: subView === 'list',
631→    },
632→  );
633→  useKeyboardShortcut(
634→    {
635→      key: 'e',
636→      meta: true,
637→    },
638→    handleEdit,
639→    {
640→      enabled: subView === 'list',
641→    },
642→  );
643→  useKeyboardShortcut(
644→    {
645→      key: 'Backspace',
646→      meta: true,
647→    },
648→    handleDelete,
649→    {
650→      enabled: subView === 'list',
651→    },
652→  );
653→  useKeyboardShortcut({ key: 'Escape' }, handleEscape, {
654→    enabled: subView !== 'list',
655→    preventDefault: false,
656→  });
657→
658→  const dropdownSections: DropdownSection[] = useMemo(
659→    () => [
660→      {
661→        title: 'Actions',
662→        actions: [
663→          {
664→            label: 'Insert',
665→            shortcut: <Kbd keys={['↵']} />,
666→            onClick: handleInsert,
667→          },
668→          createCopyAction(
669→            {
670→              content: selectedEntry?.content ?? '',
671→              title: 'Copy',
672→              shortcut: (
673→                <Kbd
674→                  keys={[
675→                    '⌘',
676→                    'C',
677→                  ]}
678→                />
679→              ),
680→              hudIcon: <SnippetHUDIcon />,
681→            },
682→            showHUD,
683→          ),
684→          {
685→            label: 'Edit',
686→            shortcut: (
687→              <Kbd
688→                keys={[
689→                  '⌘',
690→                  'E',
691→                ]}
692→              />
693→            ),
694→            onClick: handleEdit,
695→          },
696→          {
697→            label: 'Create Snippet',
698→            shortcut: (
699→              <Kbd
700→                keys={[
701→                  '⌘',
702→                  'N',
703→                ]}
704→              />
705→            ),
706→            onClick: handleCreate,
707→          },
708→        ],
709→      },
710→      {
711→        title: 'Danger Zone',
712→        actions: [
713→          {
714→            label: 'Delete',
715→            shortcut: (
716→              <Kbd
717→                keys={[
718→                  '⌘',
719→                  '⌫',
720→                ]}
721→              />
722→            ),
723→            onClick: handleDelete,
724→          },
725→        ],
726→      },
727→    ],
728→    [
729→      selectedEntry?.content,
730→      handleInsert,
731→      handleEdit,
732→      handleCreate,
733→      handleDelete,
734→      showHUD,
735→    ],
736→  );
737→
738→  const activeDescendantId =
739→    totalItemCount > 0 ? `list-item-${selectedIndex}` : undefined;
740→
741→  if (subView !== 'list') {
742→    const formTitle = subView === 'edit' ? 'Edit Snippet' : 'Create Snippet';
743→    return (
744→      <>
745→        <SearchBar
746→          value=""
747→          onChange={() => {}}
748→          placeholder={formTitle}
749→          breadcrumbs={[
750→            ...nav.breadcrumbs,
751→            {
752→              label: 'Snippets',
753→              onBack: handleEscape,
754→            },
755→          ]}
756→        />
757→        <div className="command-palette__body">
758→          <div className="command-palette__list-container">
759→            <EditSnippetView
760→              snippet={subView === 'edit' ? editingSnippet : undefined}
761→              onSubmit={handleFormSubmit}
762→            />
763→          </div>
764→        </div>
765→        <ActionPanel
766→          contextLabel={formTitle}
767→          actions={[
768→            {
769→              label: 'Submit',
770→              shortcut: (
771→                <Kbd
772→                  keys={[
773→                    '⌘',
774→                    '↵',
775→                  ]}
776→                />
777→              ),
778→            },
779→          ]}
780→          dropdownOpen={false}
